                  <span className="text-xs">가상 계좌 발급</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
                <div className="flex flex-col items-center flex-1">
                  <span className="text-purple-500 text-2xl mb-1">💳</span>
                  <span className="text-xs">결제 완료</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
                <div className="flex flex-col items-center flex-1">
