                  <span className="text-xs font-bold">0건</span>
                </div>
              </div>
            </div>
          )}
          {/* 탭별 컨텐츠: 마이페이지가 아닐 때만 보여줌 */}
          {activeTab !== 'mypage' && (
            <div className="bg-white rounded-lg shadow p-6 min-h-[600px]">
              {activeTab === 'coupons' && (
                <div>
                  {/* 상단 요약/입력 영역 */}
