                <div>
                  <div className="font-bold mb-2">결제내역</div>
                  <table className="w-full text-sm border">
                    <thead>
                      <tr className="bg-gray-50">
                        <th className="p-2 border">결제번호</th>
                        <th className="p-2 border">금액</th>
                        <th className="p-2 border">수단</th>
                        <th className="p-2 border">날짜</th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr>
                        <td className="p-2 border">P20240601-001</td>
                        <td className="p-2 border">50,000원</td>
                        <td className="p-2 border">카드</td>
                        <td className="p-2 border">2024-06-01</td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              )}
              {activeTab === 'favorits' && (
                <div>
                  <div className="font-bold mb-2">즐겨찾기한 서비스</div>
                  {favoriteProducts.length === 0 ? (
                    <div className="text-center py-12">
                      <div className="text-gray-400 mb-4">
                        <svg className="mx-auto h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                        </svg>
                      </div>
                      <p className="text-gray-500 text-lg">즐겨찾기한 상품이 없습니다.</p>
                      <p className="text-gray-400 text-sm mt-2">상품을 즐겨찾기에 추가해보세요.</p>
                    </div>
                  ) : (
                    <>
                      <div className="flex justify-end mb-4">
                        <button
                          onClick={handleRemoveAllFavorites}
                          className="text-red-600 hover:text-red-700 text-sm font-medium"
                        >
                          전체 삭제
                        </button>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                        {favoriteProducts.map((product) => (
                          <ProductCard
                            key={product.id}
                            product={product}
                            isFavorite={true}
                            onFavoriteToggle={toggleFavorite}
                            categoryIcon={categoryIcon[product.category] || categoryIcon['기타']}
                          />
                        ))}
                      </div>
                    </>
                  )}
                </div>
              )}
              {activeTab === 'settings' && (
                <div>
                  <div className="font-bold mb-2">환경설정</div>
                  <div className="text-sm text-gray-700">알림 설정, 비밀번호 변경 등 환경설정 기능이 여기에 표시됩니다.</div>
                </div>
              )}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default UserPage;
